				if nums[i] >= nums[i+1] {
					valid = false
					break
				}
			}
			if !valid {
				continue
			}
			// Check middle part: p...q strictly decreasing
			for i := p; i < q; i++ {
				if nums[i] <= nums[i+1] {
					valid = false
					break
				}
			}
			if !valid {
